import React, { useEffect, useState } from 'react';
import { auditAPI } from '../services/api';
import {
  PageHeader, Card, Table, Badge, Input, Select, toast,
} from '../components/ui';

const ACTION_COLORS = {
  LOGIN:           'blue',
  LOGIN_FAILED:    'red',
  LOGOUT:          'neutral',
  EMPLOYEE_CREATE: 'green',
  EMPLOYEE_UPDATE: 'orange',
  EMPLOYEE_DELETE: 'red',
  LEAVE_APPLY:     'blue',
  LEAVE_APPROVE:   'green',
  LEAVE_REJECT:    'red',
  PAYROLL_GENERATE: 'orange',
  PAYROLL_FINALIZE: 'green',
  ROLE_CHANGE:      'purple',
};

export default function AuditLogs() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    search: '', action: '', resource: '',
  });
  const [page, setPage] = useState(0);
  const PAGE_SIZE = 50;

  const loadLogs = async () => {
    setLoading(true);
    try {
      const params = {
        limit: PAGE_SIZE,
        offset: page * PAGE_SIZE,
      };
      if (filters.action) params.action = filters.action;
      if (filters.resource) params.resource = filters.resource;

      const { data } = await auditAPI.list(params);
      setLogs(data);
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load audit logs', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    loadLogs();
  }, [page, filters.action, filters.resource]);

  const filteredLogs = filters.search
    ? logs.filter(
        (l) =>
          l.user_email?.toLowerCase().includes(filters.search.toLowerCase()) ||
          l.detail?.toLowerCase().includes(filters.search.toLowerCase()) ||
          l.action?.toLowerCase().includes(filters.search.toLowerCase())
      )
    : logs;

  const cols = [
    {
      key: 'created_at',
      label: 'Timestamp',
      render: (r) => (
        <span style={{ fontSize: 13, color: 'var(--text-light)', whiteSpace: 'nowrap' }}>
          {new Date(r.created_at).toLocaleString('en-IN', {
            day: '2-digit',
            month: 'short',
            hour: '2-digit',
            minute: '2-digit',
          })}
        </span>
      ),
    },
    {
      key: 'user_email',
      label: 'User',
      render: (r) => (
        <span style={{ fontWeight: 500, fontSize: 13 }}>{r.user_email || '—'}</span>
      ),
    },
    {
      key: 'action',
      label: 'Action',
      render: (r) => (
        <Badge variant={ACTION_COLORS[r.action] || 'neutral'}>
          {r.action}
        </Badge>
      ),
    },
    { key: 'resource', label: 'Resource' },
    {
      key: 'detail',
      label: 'Detail',
      render: (r) => (
        <span
          style={{ maxWidth: 250, display: 'inline-block', fontSize: 13 }}
          className="truncate"
        >
          {r.detail || '—'}
        </span>
      ),
    },
    {
      key: 'ip_address',
      label: 'IP Address',
      render: (r) => (
        <span style={{ fontSize: 13, fontFamily: 'monospace', color: 'var(--gray-500)' }}>
          {r.ip_address || '—'}
        </span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      render: (r) => (
        <Badge variant={r.status === 'success' ? 'success' : r.status === 'failed' ? 'danger' : 'neutral'}>
          {r.status}
        </Badge>
      ),
    },
  ];

  return (
    <>
      <PageHeader
        title="Audit Logs"
        subtitle="Track all system actions and security events"
      />

      {/* Filters */}
      <Card style={{ marginBottom: 20, padding: 16 }}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-end' }}>
          <div style={{ flex: 1, minWidth: 200 }}>
            <Input
              placeholder="Search by user, detail..."
              value={filters.search}
              onChange={(e) => setFilters({ ...filters, search: e.target.value })}
              style={{ marginBottom: 0 }}
              id="audit-search"
            />
          </div>
          <div style={{ minWidth: 180 }}>
            <Select
              value={filters.action}
              onChange={(e) => { setFilters({ ...filters, action: e.target.value }); setPage(0); }}
              style={{ marginBottom: 0 }}
              id="audit-action-filter"
            >
              <option value="">All Actions</option>
              {Object.keys(ACTION_COLORS).map((a) => (
                <option key={a} value={a}>{a}</option>
              ))}
            </Select>
          </div>
          <div style={{ minWidth: 150 }}>
            <Select
              value={filters.resource}
              onChange={(e) => { setFilters({ ...filters, resource: e.target.value }); setPage(0); }}
              style={{ marginBottom: 0 }}
              id="audit-resource-filter"
            >
              <option value="">All Resources</option>
              {['auth', 'user', 'employee', 'leave', 'attendance', 'payroll', 'onboarding'].map((r) => (
                <option key={r} value={r}>{r}</option>
              ))}
            </Select>
          </div>
        </div>
      </Card>

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <Table cols={cols} rows={filteredLogs} loading={loading} emptyMsg="No audit logs found" />

        {/* Pagination */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '12px 20px',
            borderTop: '1px solid var(--border-color)',
            fontSize: 13,
            color: 'var(--gray-500)',
          }}
        >
          <span>
            Showing {filteredLogs.length} results (page {page + 1})
          </span>
          <div style={{ display: 'flex', gap: 8 }}>
            <button
              disabled={page === 0}
              onClick={() => setPage((p) => Math.max(0, p - 1))}
              style={{
                padding: '6px 14px',
                border: '1px solid var(--border-color)',
                borderRadius: '6px',
                background: 'var(--white)',
                cursor: page === 0 ? 'not-allowed' : 'pointer',
                opacity: page === 0 ? 0.5 : 1,
                fontSize: 13,
                color: 'var(--text-dark)',
              }}
            >
              Previous
            </button>
            <button
              disabled={logs.length < PAGE_SIZE}
              onClick={() => setPage((p) => p + 1)}
              style={{
                padding: '6px 14px',
                border: '1px solid var(--border-color)',
                borderRadius: '6px',
                background: 'var(--white)',
                cursor: logs.length < PAGE_SIZE ? 'not-allowed' : 'pointer',
                opacity: logs.length < PAGE_SIZE ? 0.5 : 1,
                fontSize: 13,
                color: 'var(--text-dark)',
              }}
            >
              Next
            </button>
          </div>
        </div>
      </Card>
    </>
  );
}
